    private async Task LoadDropdowns()
    {
        var ccTask = VoucherService.GetCostCentresAsync();
        var debitTask = VoucherService.GetCashBankLedgersAsync();
        var customerTask = DropdownService.GetCustomersAsync();
        await Task.WhenAll(ccTask, debitTask, customerTask);

        CostCentres = ccTask.Result;
        CashBankLedgers = debitTask.Result;
        CustomerList = customerTask.Result;

        if (CostCentres.Any()) Voucher.CostCentreId = CostCentres[0].CostCentreId;
    }

    private List<InvoiceAllocation> GetSelectedAllocations()
        => Voucher.Allocations.Where(a => a.Order > 0 && a.SaAmount > 0 && a.InvoiceId != 0).ToList();

    private void OnAllocationSelectedChanged(InvoiceAllocation item, ChangeEventArgs e)
{
    var isChecked = e.Value is bool b && b;
    item.Order = isChecked ? 1 : 0;
    if (isChecked && item.SaAmount == 0)
    {
        item.SaAmount = item.CurrentAmount; // or item.BillAmount if you prefer
    }
    if (!isChecked)
    {
        item.SaAmount = 0;
    }
}

    private async Task OnInvoiceOkClicked()
    {
        var selectedAllocations = GetSelectedAllocations();
        decimal totalSaAmount = selectedAllocations.Sum(a => a.SaAmount);
        if (selectedAllocations.Count == 0)
        {
            await ToastService.ShowErrorAsync("Please select at least one invoice.");
            return;
        }
        if (totalSaAmount != Voucher.Amount)
        {
            await ToastService.ShowErrorAsync("Voucher amount must match selected invoice allocation.");
            return;
        }
        await ToastService.ShowSuccessAsync("Invoice allocation OK.");
    }

    private async Task OnCustomerChangedAsync()
    {
        await JS.InvokeVoidAsync("console.log", "[OnCustomerChangedAsync] Fired");
        var ledgerId = Voucher.CreditLedgerId;
        await JS.InvokeVoidAsync("console.log", $"[OnCustomerChangedAsync] ledgerId value before if: {ledgerId}");
        if (ledgerId > 0)
        {
            CustomerBalance = await VoucherService.GetLedgerBalanceAsync((int)ledgerId);
            await JS.InvokeVoidAsync("console.log", $"[OnCustomerChangedAsync] Calling GetPendingBillsAsync for LedgerId: {ledgerId}, Request: {{ LedgerId: {ledgerId} }}");
            Voucher.Allocations = await VoucherService.GetPendingBillsAsync((int)ledgerId);
            if (IsAutoMode) AutoAllocate();
            StateHasChanged();
        }
        else
        {
            Voucher.CreditLedgerId = 0;
            CustomerBalance = 0;
            Voucher.Allocations.Clear();
            StateHasChanged();
        }
    }

    private void OnAmountChanged()
    {
        if (IsAutoMode) AutoAllocate();
    }

    private async Task SetInvoiceMode(bool auto)
    {
        System.Diagnostics.Debug.WriteLine($"[SetInvoiceMode] Called with auto={auto}, LedgerId={Voucher.CreditLedgerId}");
        IsAutoMode = auto;
        if (auto)
        {
            AutoAllocate();
        }
        else
        {
            // Manual mode: fetch pending bills and map to allocations using DI ReceiptService
            if (Voucher.CreditLedgerId > 0)
            {
                try
                {
                    await JS.InvokeVoidAsync("console.log", $"[SetInvoiceMode] Fetching pending bills for LedgerId: {Voucher.CreditLedgerId}");
                }
                catch (Exception ex)
                {
                    System.Diagnostics.Debug.WriteLine($"[SetInvoiceMode] JSInterop error: {ex.Message}");
                }
                var bills = await VoucherService.GetPendingBillsAsync((int)Voucher.CreditLedgerId);
                try
                {
                    await JS.InvokeVoidAsync("console.log", $"[SetInvoiceMode] Pending bills fetched:", bills);
                }
                catch (Exception ex)
                {
                    System.Diagnostics.Debug.WriteLine($"[SetInvoiceMode] JSInterop error: {ex.Message}");
                }
                // Map PendingBill to InvoiceAllocation using correct property names
                Voucher.Allocations = bills.Select(b => new InvoiceAllocation
                {
                    InvoiceId = b.InvoiceId,
                    InvoiceNo = b.InvoiceNo,
                    InvoiceDate = b.InvoiceDate,
                    CreditDays = b.CreditDays,
                    BillAmount = b.BillAmount,
                    CurrentAmount = b.CurrentAmount,
                    SaAmount = 0,
                    Order = 0
                }).ToList();
            }
            StateHasChanged();
        }
    }

    private void AutoAllocate()
{
    if (Voucher.Amount <= 0 || Voucher.Allocations == null)
        return;

    decimal remaining = Voucher.Amount;

    // FIFO: oldest first
    var sortedBills = Voucher.Allocations
        .OrderBy(x => x.InvoiceDate)
        .ToList();

    foreach (var bill in sortedBills)
    {
        if (remaining <= 0)
        {
            bill.SaAmount = 0;
            continue;
        }

        var alloc = Math.Min(remaining, bill.CurrentAmount);

        bill.SaAmount = alloc;

        remaining -= alloc;
    }

    StateHasChanged();
}

    private void OnManualSaAmountChanged(InvoiceAllocation item, ChangeEventArgs e)
    {
        if (decimal.TryParse(e.Value?.ToString(), out var val))
        {
            item.SaAmount = Math.Min(Math.Max(val, 0), item.CurrentAmount);
        }
    }

    private void OnOrderChanged(InvoiceAllocation item, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var val))
        {
            item.Order = Math.Max(val, 1);
        }
    }

